import anthropic
import json

client = anthropic.Anthropic()

def cascade_classify(task: str) -> tuple[str, str]:
    """Route to Haiku; escalate to Opus if complexity flag is set."""
    haiku_resp = client.messages.create(
        model="claude-haiku-4-5",
        max_tokens=64,
        messages=[
            {
                "role": "user",
                "content": (
                    f"Can you answer this confidently with high accuracy? Reply JSON only: "
                    f'{{"can_answer": true/false}}. Task: {task}'
                ),
            }
        ],
    )
    try:
        verdict = json.loads(haiku_resp.content[0].text)
        can_answer = verdict.get("can_answer", False)
    except Exception:
        can_answer = False

    model = "claude-haiku-4-5" if can_answer else "claude-opus-4-8"
    resp = client.messages.create(
        model=model,
        max_tokens=1024,
        messages=[{"role": "user", "content": task}],
    )
    return model, resp.content[0].text
